class Solution {
public:
    bool canTransform(string start, string result) {
        int i = 0, j = 0;
        while (i < start.size() && j < result.size()) {
            if (start[i] == result[j]) {
                i++; j++;
            } else if (start[i] == 'X' && result[j] == 'R') {
                while (i < start.size() && start[i] != 'L') i++;
                if (i == start.size()) return false;
                i++;
            } else if (start[i] == 'X' && result[j] == 'L') {
                while (j < result.size() && result[j] != 'R') j++;
                if (j == result.size()) return false;
                j++;
            } else {
                return false;
            }
        }
        return i == start.size() && j == result.size();
    }
};
